import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

@Component({
  selector: 'app-student-profile',
  templateUrl: './student-profile.component.html',
  styleUrls: ['./student-profile.component.css'],
})
export class StudentProfileComponent {
  profileForm: FormGroup;
  submitted = false;

  constructor(private fb: FormBuilder) {
    // Reactive Forms are defined in the component class, which keeps
    // validation logic explicit and testable (Hands-On 7, Task 3).
    this.profileForm = this.fb.group({
      name: ['', [Validators.required, Validators.minLength(2)]],
      email: ['', [Validators.required, Validators.email]],
      semester: [1, [Validators.required, Validators.min(1), Validators.max(8)]],
    });
  }

  get name() {
    return this.profileForm.get('name')!;
  }

  get email() {
    return this.profileForm.get('email')!;
  }

  get semester() {
    return this.profileForm.get('semester')!;
  }

  onSubmit(): void {
    this.submitted = true;
    if (this.profileForm.valid) {
      console.log('Profile submitted:', this.profileForm.value);
    }
  }
}
<section aria-labelledby="profile-heading">
  <h1 id="profile-heading">My Profile</h1>

  <form [formGroup]="profileForm" (ngSubmit)="onSubmit()" class="profile-form" novalidate>
    <div class="form-field">
      <label for="name">Full name</label>
      <input id="name" type="text" formControlName="name" />
      <p class="field-error" *ngIf="name.invalid && (name.touched || submitted)">
        Name is required (min. 2 characters).
      </p>
    </div>

    <div class="form-field">
      <label for="email">Email</label>
      <input id="email" type="email" formControlName="email" />
      <p class="field-error" *ngIf="email.invalid && (email.touched || submitted)">
        Enter a valid email address.
      </p>
    </div>

    <div class="form-field">
      <label for="semester">Semester</label>
      <input id="semester" type="number" min="1" max="8" formControlName="semester" />
      <p class="field-error" *ngIf="semester.invalid && (semester.touched || submitted)">
        Semester must be between 1 and 8.
      </p>
    </div>

    <button type="submit" class="btn btn-primary" [disabled]="profileForm.invalid">
      Save profile
    </button>

    <p class="success-msg" *ngIf="submitted && profileForm.valid" role="status">
      Profile saved successfully.
    </p>
  </form>
</section>
